class Admin_Model_Complaint extends Admin_Model_Base_Complaint
{

    /**
     * @param array $userData
     * @param array|null $companyData
     * @param array $addressData
     * @param array|null $deliveryData
     * @return self
     * @throws Exception
     */
    public static function createComplaint(array $userData, ?array $companyData, array $addressData, ?array $deliveryData): self {
        $complaint = new Admin_Model_Complaint();

        $complaint->Name = $userData['Name'];
        $complaint->Email = $userData['Email'];
        $complaint->Phone = $userData['Phone'];
        $complaint->Package = $userData['Package'];

        $complaint->InvoiceStreet = $addressData['Street'];
        $complaint->InvoiceCity = $addressData['City'];
        $complaint->InvoiceZipCode = $addressData['ZipCode'];
        $complaint->InvoiceCountry_ID = $addressData['Country_ID'];
        $complaint->DateCreated = date('Y-m-d H:i:s');

        if ($companyData) {
            $complaint->CompanyName = $companyData['CompanyName'];
            $complaint->IC = $companyData['IC'];
            $complaint->DIC = $companyData['DIC'];
        }

        if ($deliveryData) {
            $complaint->DeliveryName = $deliveryData['Name'];
            $complaint->DeliveryStreet = $deliveryData['Street'];
            $complaint->DeliveryCity = $deliveryData['City'];
            $complaint->DeliveryZipCode = $deliveryData['ZipCode'];
            $complaint->DeliveryCountry_ID = $deliveryData['Country_ID'];
        }

        $complaint->save();

        return $complaint;
    }

}